#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include "backprop.h"
#include <cuda_runtime.h>

static unsigned int num_threads = THREADS;
static unsigned int num_blocks = 0;

int platform_id_inuse = 0;            
int device_id_inuse = 0;              
cl_device_type device_type = CL_DEVICE_TYPE_GPU;

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

int bpnn_train_cuda(BPNN *net, float *eo, float *eh)
{
	int in, hid, out;
	float out_err, hid_err;

	in = net->input_n;
	hid = net->hidden_n;
	out = net->output_n;

	float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
	float * partial_sum;
	float sum;
	int num_blocks = in / BLOCK_SIZE;

	input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

	int m = 0;
	for (int k = 0; k <= in; k++) {
		for (int j = 0; j <= hid; j++) {
		input_weights_one_dim[m] = net->input_weights[k][j];
		input_weights_prev_one_dim[m] = net-> input_prev_weights[k][j];
	    m++;
		}
	}

	float *d_input_ocl;
	float *d_input_hidden_ocl;
	float *d_output_hidden_ocl;
	float *d_hidden_partial_sum;
	float *d_hidden_delta_ocl;
	float *d_input_prev_weights_ocl;

	cudaError_t err;

	err = cudaMalloc((void**)&d_input_ocl, (in + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_input_ocl\n"); return -1;}
	err = cudaMalloc((void**)&d_input_hidden_ocl, (in + 1) * (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_input_hidden_ocl\n"); return -1;}
	err = cudaMalloc((void**)&d_output_hidden_ocl, (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_output_hidden_ocl\n"); return -1;}
	err = cudaMalloc((void**)&d_hidden_partial_sum, num_blocks * WIDTH * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_hidden_partial_sum\n"); return -1;}
	err = cudaMalloc((void**)&d_hidden_delta_ocl, (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_hidden_delta_ocl\n"); return -1;}
	err = cudaMalloc((void**)&d_input_prev_weights_ocl, (in + 1) * (hid + 1) * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_input_prev_weights_ocl\n"); return -1;}

	printf("Performing GPU computation\n");

	err = cudaMemcpy(d_input_ocl, net->input_units, (in + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_ocl\n"); return -1; }

	err = cudaMemcpy(d_input_hidden_ocl, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_hidden_ocl\n"); return -1; }

	dim3 local_work(BLOCK_SIZE, BLOCK_SIZE, 1);
	dim3 global_work(BLOCK_SIZE, BLOCK_SIZE * num_blocks, 1);

	// Allocate shared memory for input_node and weight_matrix
	// input_node size: HEIGHT floats
	// weight_matrix size: HEIGHT * WIDTH floats
	size_t shared_mem_size = HEIGHT * sizeof(float) + HEIGHT * WIDTH * sizeof(float);

	// Launch kernel bpnn_layerforward_ocl
	bpnn_layerforward_ocl<<<dim3(global_work.x, global_work.y), dim3(local_work.x, local_work.y), shared_mem_size>>>(
		d_input_ocl,
		d_output_hidden_ocl,
		d_input_hidden_ocl,
		d_hidden_partial_sum,
		NULL, // input_node pointer in shared memory, will be set inside kernel
		NULL, // weight_matrix pointer in shared memory, will be set inside kernel
		in,
		hid);

	err = cudaGetLastError();
	if(err != cudaSuccess) { printf("ERROR: kernel launch bpnn_layerforward_ocl failed: %s\n", cudaGetErrorString(err)); return -1; }

	err = cudaMemcpy(partial_sum, d_hidden_partial_sum, num_blocks * WIDTH * sizeof(float), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy partial_sum\n"); return -1; }

	for (int j = 1; j <= hid; j++) {
		sum = 0.0f;
		for (int k = 0; k < num_blocks; k++) {
		sum += partial_sum[k * hid + j-1] ;
    }
		sum += net->input_weights[0][j];
		net-> hidden_units[j] = 1.0f / (1.0f + expf(-sum));
	}

	bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
	bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
	bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
	bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

	err = cudaMemcpy(d_hidden_delta_ocl, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy hidden_delta_ocl\n"); return -1; }

	err = cudaMemcpy(d_input_prev_weights_ocl, input_weights_prev_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_prev_weights_ocl\n"); return -1; }

	err = cudaMemcpy(d_input_hidden_ocl, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_hidden_ocl\n"); return -1; }

	// Launch kernel bpnn_adjust_weights_ocl
	bpnn_adjust_weights_ocl<<<dim3(global_work.x, global_work.y), dim3(local_work.x, local_work.y)>>>(
		d_hidden_delta_ocl,
		hid,
		d_input_ocl,
		in,
		d_input_hidden_ocl,
		d_input_prev_weights_ocl);

	err = cudaGetLastError();
	if(err != cudaSuccess) { printf("ERROR: kernel launch bpnn_adjust_weights_ocl failed: %s\n", cudaGetErrorString(err)); return -1; }

	err = cudaMemcpy(net->input_units, d_input_ocl, (in + 1) * sizeof(float), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_ocl back\n"); return -1; }

	err = cudaMemcpy(input_weights_one_dim, d_input_hidden_ocl, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy input_hidden_ocl back\n"); return -1; }

	cudaFree(d_input_ocl);
	cudaFree(d_output_hidden_ocl);
	cudaFree(d_input_hidden_ocl);
	cudaFree(d_hidden_partial_sum);
	cudaFree(d_input_prev_weights_ocl);
	cudaFree(d_hidden_delta_ocl);

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);

	*eo = out_err;
	*eh = hid_err;

	return 0;
}

int main(int argc, char** argv)
{
	return setup(argc, argv);
}
